import jsonschema
from llama_stack_client import LlamaStack

TOOL_SCHEMA = {
    'type': 'object',
    'properties': {
        'tool_id': {'type': 'string'},
        'parameters': {'type': 'object'},
        'response': {'type': 'object'}
    },
    'required': ['tool_id']
}

def detect_schema_loops(stack_session):
    history = stack_session.get_session_history()
    schema_errors = 0
    consecutive_errors = 0

    for turn in reversed(history[-10:]):
        if 'tool_response' in turn:
            try:
                jsonschema.validate(turn['tool_response'], TOOL_SCHEMA)
                consecutive_errors = 0
            except jsonschema.ValidationError:
                schema_errors += 1
                consecutive_errors += 1
                if consecutive_errors >= 3:
                    return {'schema_loop': True, 'consecutive_errors': consecutive_errors}
        else:
            consecutive_errors = 0

    return {'schema_loop': False, 'total_errors': schema_errors}
